+// TODO: move into a file Utils.h
+template<typename T>
+size_t argMax(const typename MetricSpaceAligner<T>::Vector& v)
+{
+	T maxVal(0);
+	size_t maxIdx(0);
+	for (int i = 0; i < v.size(); ++i)
+	{
+		if (v[i] > maxVal)
+		{
+			maxVal = v[i];
+			maxIdx = i;
+		}
+	}
+	return maxIdx;
+}
